/**
 * Normalized Task Execution Metadata
 * Maps to [[Autonomous-Execution-States]]
 */
export type ExecutionState =
	| "queued" // Task is ready but waiting for resources
	| "ready" // Task has all prerequisites met
	| "running" // Agent is actively working on the task
	| "blocked" // Task is waiting on a dependency
	| "completed" // Task finished successfully
	| "failed" // Task encountered a fatal error
	| "skipped"; // Task is intentionally bypassed

export interface TaskExecutionMetadata {
	state: ExecutionState;
	intent?: string; // Detailed description or prompt for the agent
	suggestedRole?: string; // Role of the agent (e.g., 'frontend', 'backend', 'qa')
	parallelizable?: boolean; // Whether this task can run concurrently with others in its group
	dependsOn?: string[]; // Array of task IDs that must complete first
	errorMessage?: string; // Reason for failure, if applicable
}

/**
 * Common Task Status
 */
export type NormalizedTaskStatus =
	| "completed"
	| "in-progress"
	| "not-started"
	| "failed"
	| "blocked"
	| "skipped";

/**
 * Normalized Task representation across SpecKit, OpenSpec, etc.
 * Maps to [[Task-Normalization-Contract]]
 */
export interface NormalizedTask {
	id: string; // Global or spec-scoped unique ID
	title: string; // Short description
	status: NormalizedTaskStatus;
	source: {
		system: string; // e.g., "SpecKit", "OpenSpec"
		filePath: string; // Absolute path to the source file
		line?: number; // Original line number for navigation
		isUnsupported?: boolean; // True if the task couldn't be fully parsed
	};
	metadata: {
		phase?: string; // Phase or grouping
		priority?: string;
		complexity?: string;
	};
	execution?: TaskExecutionMetadata;
}

export interface TaskProvider {
	/**
	 * Unique identifier for the provider (e.g., 'speckit', 'openspec').
	 */
	readonly name: string;

	/**
	 * Determine if this provider handles the specified file.
	 */
	canHandle(filePath: string): boolean;

	/**
	 * Read and normalize tasks from a given file.
	 */
	getTasks(specId: string, filePath: string): Promise<NormalizedTask[]>;
}
import type {
	NormalizedTask,
	TaskProvider,
	NormalizedTaskStatus,
} from "./task-model";
import { parseTasksFromFile, type TaskGroup } from "../../utils/task-parser";
import { SPEC_SYSTEM_MODE } from "../../constants";

export class SpecKitTaskProvider implements TaskProvider {
	readonly name = SPEC_SYSTEM_MODE.SPECKIT;

	canHandle(filePath: string): boolean {
		if (filePath.includes("openspec/")) {
			return false;
		}
		return filePath.includes(".specify") || filePath.includes("specs/");
	}

	getTasks(specId: string, filePath: string): Promise<NormalizedTask[]> {
		try {
			const groups = parseTasksFromFile(filePath);
			if (!groups || groups.length === 0) {
				return Promise.resolve([]);
			}

			return Promise.resolve(this.normalizeGroups(specId, filePath, groups));
		} catch (error) {
			// Degrade clearly for unsupported/unparseable files
			return Promise.resolve([
				{
					id: `unsupported-${Date.now()}`,
					title: "Failed to parse tasks.md",
					status: "not-started",
					source: {
						system: this.name,
						filePath,
						isUnsupported: true,
					},
					metadata: {},
				},
			]);
		}
	}

	private normalizeGroups(
		specId: string,
		filePath: string,
		groups: TaskGroup[]
	): NormalizedTask[] {
		const normalized: NormalizedTask[] = [];

		for (const group of groups) {
			for (const task of group.tasks) {
				normalized.push({
					id: `${specId}-${task.id}`, // Scope IDs to spec to ensure uniqueness
					title: task.title,
					status: this.mapStatus(task.status),
					source: {
						system: this.name,
						filePath,
						line: task.line,
					},
					metadata: {
						phase: task.phase || group.name,
						priority: task.priority,
						complexity: task.complexity,
					},
					execution: {
						state: this.mapExecutionState(task.status),
					},
				});
			}
		}

		return normalized;
	}

	private mapStatus(status: string): NormalizedTaskStatus {
		switch (status) {
			case "completed":
				return "completed";
			case "in-progress":
				return "in-progress";
			default:
				return "not-started";
		}
	}

	private mapExecutionState(
		status: string
	): "queued" | "running" | "completed" | "ready" {
		switch (status) {
			case "completed":
				return "completed";
			case "in-progress":
				return "running";
			default:
				return "ready";
		}
	}
}
